import{c as i,Q as l,j as a,m as d}from"./chunks/framework.DVkeSyfh.js";const _=JSON.parse('{"title":"Идеи","description":"","frontmatter":{},"headers":[],"relativePath":"ru/ideas.md","filePath":"ru/ideas.md","lastUpdated":1781921330000}'),s={name:"ru/ideas.md"};function t(c,e,r,o,p,n){return l(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="идеи" tabindex="-1">Идеи <a class="header-anchor" href="#идеи" aria-label="Permalink to &quot;Идеи&quot;">​</a></h1><p>Эта страница хранит крупные идеи для рабочих процессов, которые еще не реализованы. Это продуктовые заметки, а не описание текущего поведения или стабильных API-контрактов.</p><h2 id="smart-set-builder-по-seed-трекам" tabindex="-1">Smart Set Builder по seed-трекам <a class="header-anchor" href="#smart-set-builder-по-seed-трекам" aria-label="Permalink to &quot;Smart Set Builder по seed-трекам&quot;">​</a></h2><p>Добавить отдельный UI-режим, который генерирует вариативный список кандидатов для DJ-сета на основе 3-10 выбранных seed-треков. Цель не просто найти &quot;еще похожие треки&quot;, а сделать слой куратора поверх существующих моделей, который выдает полезную последовательность для прослушивания, digging или подготовки сета.</p><p>Первую версию можно сделать без обучения новой модели:</p><ul><li>использовать MERT для музыкальной и аудиальной близости;</li><li>использовать MAEST как подсказку по жанру и текстуре;</li><li>использовать SONARA для BPM, энергии и ритмической совместимости;</li><li>использовать promoted classifier scores, например <code>abstract_edge</code>, <code>break_energy</code> или <code>voice_presence</code>, как сигналы предпочтения и исключения;</li><li>исключать уже размеченные, лайкнутые, просмотренные или недавно показанные треки, если пользователь хочет discovery, а не подтверждение уже найденного.</li></ul><p>Возможные режимы:</p><ul><li><code>similar_crate</code>: держаться близко к seed-трекам и ранжировать кандидатов по сильному совпадению MERT, MAEST, SONARA и classifier scores.</li><li><code>weird_adjacent</code>: сохранять достаточную похожесть, но предпочитать треки с необычным расхождением моделей или более экспериментальной текстурой.</li><li><code>balanced_set</code>: генерировать DJ-ориентированный список с bridge-треками, совместимостью BPM/энергии и меньшим повторением слишком похожих треков подряд.</li><li><code>discovery</code>: допускать более рискованные кандидаты и резервировать часть списка под low-confidence треки, которые могут найти новые удачные positives для классификаторов.</li></ul><p>Полезные контролы:</p><ul><li>выбор seed-треков;</li><li>длина списка;</li><li>уровень diversity;</li><li>energy curve: warmup, balanced, peak или wave;</li><li>classifier targets и avoid rules;</li><li>исключение лайкнутых, размеченных, просмотренных или уже экспортированных треков;</li><li>опциональные ограничения по BPM/key compatibility.</li></ul><p>Результат должен объяснять, почему каждый трек попал в список, например <code>similar_to_seed</code>, <code>bridge</code>, <code>weird_adjacent</code> или <code>classifier_match</code>, и показывать базовые MERT/MAEST/SONARA/classifier scores для ручной проверки.</p><p>Возможная форма API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/set-builder/generate</span></span></code></pre></div><p>Поля входа:</p><ul><li><code>seed_track_ids</code></li><li><code>limit</code></li><li><code>mode</code></li><li><code>diversity</code></li><li><code>energy_curve</code></li><li><code>classifier_targets</code></li><li><code>exclude_reviewed</code></li></ul><p>Поля выхода:</p><ul><li>ранжированные track rows;</li><li>причина выбора;</li><li>similarity и diversity scores;</li><li>релевантные classifier scores;</li><li>опциональные данные порядка сета, например energy step или bridge target.</li></ul><p>Дальше можно добавить отправку выбранных треков в Rhythm Lab, отметку просмотренных кандидатов, экспорт M3U/XLSX или сохранение сессий для итеративного active-learning workflow.</p>',18)])])}const m=i(s,[["render",t]]);export{_ as __pageData,m as default};
